  private apiClient: ApiClient | null = null;
  private memoryManager: MemoryManager | null = null;
  private initialized = false;
  private lastDecision: DecisionRecord | null = null;

  constructor(
    private storageConfig: StorageConfig = { maxEntries: 1000, ttl: 3600000, persistToDisk: true },
    private contextConfig: ContextConfig = { windowSize: 50, priorityThreshold: 0.5, compressionEnabled: true },
    private decisionConfig: DecisionConfig = { strategy: 'hybrid', confidenceThreshold: 0.7, retryPolicy: 'exponential-backoff' }
  ) {}

  async initialize(): Promise<void> {
    if (this.initialized) return;

    this.apiClient = new ApiClient();
    this.memoryManager = new MemoryManager();
    this.initialized = true;
  }

