      metadata: {
        createdAt: Date.now(),
        updatedAt: Date.now(),
        accessCount: 0
      }
    };

    if (this.memoryManager) {
      this.memoryManager.add(newEntry);
    }

    return newEntry;
  }

  async retrieve(id: string): Promise<StorageEntry | null> {
    await this.ensureInitialized();

    if (this.memoryManager) {
      return this.memoryManager.get(id) as StorageEntry | null;
    }
    return null;
  }

  async delete(id: string): Promise<boolean> {
    await this.ensureInitialized();

    if (this.memoryManager) {
      this.memoryManager.remove(id);
      return true;
    }
    return false;
  }

  async list(type?: StorageEntry['type']): Promise<StorageEntry[]> {
    await this.ensureInitialized();

    if (this.memoryManager) {
      const all = this.memoryManager.getAll();
      if (type) {
        return all.filter(e => (e as StorageEntry).type === type);
      }
      return all as StorageEntry[];
    }
    return [];
  }

