    await this.ensureInitialized();

    const newChunk: ContextChunk = {
      ...chunk,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    };

    if (this.memoryManager) {
      this.memoryManager.add(newChunk);
    }

    return newChunk;
  }

