  }

  // ===== RESET API =====

  async reset(): Promise<void> {
    this.memoryManager?.clear();
    this.lastDecision = null;
    this.initialized = false;
    this.apiClient = null;
    this.memoryManager = null;
  }

  // ===== PRIVATE =====

  private async ensureInitialized(): Promise<void> {
    if (!this.initialized) {
      await this.initialize();
    }
  }
}

