  addContext(source: string, content: string, priority = 0.5): ContextItem {
    const item: ContextItem = {
      id: crypto.randomUUID(),
      source,
      content,
      priority,
      timestamp: Date.now()
    };
    this.context.set(item.id, item);
    return item;
  }

